Generator<std::string> stateful_gen() {
    // 'prefix' and 'modification_count' live in the coroutine frame (heap).
    // They are NOT destroyed at each suspension — they live until destroy().
    std::string prefix = "item_";
    int modification_count = 0;
    for (int i = 0; i < 3; ++i) {
        ++modification_count;
        co_yield prefix + std::to_string(i)
               + " (mod#" + std::to_string(modification_count) + ")";
    }
    // implicit co_return: done() becomes true
}

int main() {
    std::cout << "Locals in coroutine frame survive suspensions:\n";
    auto gen = stateful_gen();
    while (gen.next()) {
        std::cout << "  " << gen.value() << "\n";
    }

    std::cout << "\ndone() tracks coroutine state:\n";
    auto gen2 = stateful_gen();
    std::cout << "start:         done=" << gen2.handle.done() << "\n";
    gen2.next();
    std::cout << "after yield 1: done=" << gen2.handle.done() << "\n";
    gen2.next();
    gen2.next();
    // One more resume: coroutine exits loop, hits return_void, final_suspend
    gen2.handle.resume();
    std::cout << "after finish:  done=" << gen2.handle.done() << "\n";

    return 0;
}

