// Infinite generator: locals (a, b) live between suspensions
Generator<long long> fibonacci() {
    long long a = 0, b = 1;
    while (true) {
        co_yield a;
        long long c = a + b;
        a = b;
        b = c;
    }
}

int main() {
    std::cout << "First 10 Fibonacci numbers:\n";
    int count = 0;
    for (long long v : fibonacci()) {
        std::cout << v << ' ';
        if (++count == 10) break; // early exit — destructor destroys the frame
    }
    std::cout << '\n';

    // Second independent generator — each fibonacci() call creates its own frame
    std::cout << "First 5 from a new generator:\n";
    count = 0;
    for (long long v : fibonacci()) {
        std::cout << v << ' ';
        if (++count == 5) break;
    }
    std::cout << '\n';
}

#include <coroutine>
#include <iostream>

// Awaitable that never suspends (await_ready = true)
struct ImmediateAwaitable {
    int value;
    bool await_ready() const noexcept { return true; }        // don't suspend
    void await_suspend(std::coroutine_handle<>) noexcept {}   // never called
    int  await_resume() noexcept { return value; }             // result of co_await
};

// Awaitable that always suspends once, then self-resumes for demo purposes
struct SuspendOnce {
    bool await_ready() const noexcept { return false; }        // always suspend
    void await_suspend(std::coroutine_handle<> h) noexcept {
        std::cout << "  [await_suspend called, resuming immediately]\n";
        h.resume();  // resume right away (in real code a scheduler would do this)
    }
    void await_resume() noexcept {}
};

// Minimal eager task (just to have a coroutine)
struct Task {
    struct promise_type {
        Task get_return_object() { return {}; }
        std::suspend_never  initial_suspend() noexcept { return {}; }
        std::suspend_never  final_suspend()   noexcept { return {}; }
        void return_void() noexcept {}
        void unhandled_exception() { std::terminate(); }
    };
};

Task demo() {
    std::cout << "before co_await ImmediateAwaitable\n";
    int v = co_await ImmediateAwaitable{42};   // await_ready=true: no suspension
    std::cout << "ImmediateAwaitable returned: " << v << "\n";

    std::cout << "before co_await SuspendOnce\n";
    co_await SuspendOnce{};                    // await_ready=false: suspends, then resumes
    std::cout << "after co_await SuspendOnce\n";
}

int main() {
    demo();   // eager: runs to completion synchronously
}

#include <coroutine>
#include <iostream>
#include <string>
#include <exception>
#include <utility>

// Task<T>: eager start (initial_suspend=never),
// stays alive after co_return (final_suspend=always)
// so the caller can read the result via get().
template<typename T>
struct Task {
    struct promise_type {
        T result;
        std::exception_ptr exception;

        Task get_return_object() {
            return Task{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_never  initial_suspend() noexcept { return {}; }  // runs immediately
        std::suspend_always final_suspend()   noexcept { return {}; }  // keep frame for get()
        void return_value(T v) { result = std::move(v); }
        void unhandled_exception() { exception = std::current_exception(); }
    };

    std::coroutine_handle<promise_type> handle_;

    explicit Task(std::coroutine_handle<promise_type> h) : handle_(h) {}
    ~Task() { if (handle_) handle_.destroy(); }
    Task(const Task&) = delete;
    Task(Task&& o) noexcept : handle_(std::exchange(o.handle_, {})) {}

    T get() {
        if (handle_.promise().exception)
            std::rethrow_exception(handle_.promise().exception);
        return handle_.promise().result;
    }
};

Task<int> square(int x) {
    std::cout << "  square(" << x << ") computing...\n";
    co_return x * x;
}

Task<std::string> greet(std::string name) {
    std::cout << "  greet(\"" << name << "\") computing...\n";
    co_return "Hello, " + name + "!";
}

int main() {
    std::cout << "Creating task for square(7):\n";
    auto t1 = square(7);
    std::cout << "Result: " << t1.get() << "\n";

    std::cout << "\nCreating task for greet(\"World\"):\n";
    auto t2 = greet("World");
    std::cout << "Result: " << t2.get() << "\n";

    std::cout << "\nTwo tasks, results used in expression:\n";
    auto ta = square(3);
    auto tb = square(4);
    std::cout << "3^2 + 4^2 = " << ta.get() + tb.get() << "\n";
}

#include <coroutine>
#include <iostream>
#include <utility>

// Task with symmetric transfer support.
// When the task finishes, final_suspend returns the continuation's handle
// instead of returning control to whoever called resume() — the stack does not grow.
struct Task {
    struct promise_type {
        std::coroutine_handle<> continuation;  // who is waiting for us to finish

        Task get_return_object() {
            return Task{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_always initial_suspend() noexcept { return {}; }

        // Symmetric transfer at the end: instead of returning to whoever called resume(),
        // control transfers directly to the continuation (if any).
        struct FinalAwaitable {
            bool await_ready() noexcept { return false; }
            std::coroutine_handle<> await_suspend(
                std::coroutine_handle<promise_type> h) noexcept
            {
                auto cont = h.promise().continuation;
                return cont ? cont : std::noop_coroutine();
            }
            void await_resume() noexcept {}
        };
        FinalAwaitable final_suspend() noexcept { return {}; }

        void return_void() noexcept {}
        void unhandled_exception() { std::terminate(); }
    };

    std::coroutine_handle<promise_type> handle_;
    explicit Task(std::coroutine_handle<promise_type> h) : handle_(h) {}
    ~Task() { if (handle_) handle_.destroy(); }
    Task(const Task&) = delete;
    Task(Task&&) = delete;

    // Awaitable interface: lets another coroutine write co_await task
    bool await_ready() noexcept { return false; }
    std::coroutine_handle<> await_suspend(std::coroutine_handle<> caller) noexcept {
        handle_.promise().continuation = caller;   // remember the caller
        return handle_;                             // symmetric transfer to this task
    }
    void await_resume() noexcept {}
};

Task step_b() {
    std::cout << "  step_b: started\n";
    std::cout << "  step_b: finished\n";
    // FinalAwaitable symmetric-transfers back to step_a
    co_return;
}

Task step_a() {
    std::cout << "step_a: before co_await step_b()\n";
    auto b = step_b();
    co_await b;   // symmetric transfer: step_a suspends, step_b runs,
                  // step_b finishes -> FinalAwaitable returns step_a's handle
    std::cout << "step_a: after co_await step_b()\n";
    co_return;
}

int main() {
    std::cout << "main: creating step_a\n";
    auto a = step_a();
    std::cout << "main: first resume -> enters step_a\n";
    a.handle_.resume();
    std::cout << "main: step_a has finished\n";
}
